import{_ as n,o as a,c as e,ak as p,an as i}from"./chunks/framework.q3eGiPa5.js";const _=JSON.parse('{"title":"Linux太好用了！","description":"","frontmatter":{},"headers":[],"relativePath":"Note/I like Linux!/index.md","filePath":"Note/I like Linux!/index.md","lastUpdated":0}'),t={name:"Note/I like Linux!/index.md"};function o(s,r,d,b,l,u){return a(),e("div",null,[...r[0]||(r[0]=[p('<h1 id="linux太好用了" tabindex="-1">Linux太好用了！ <a class="header-anchor" href="#linux太好用了" aria-label="Permalink to “Linux太好用了！”">​</a></h1><p>最近几天，我被Windows折磨的实在受不了了，所以我就尝试转到Linux</p><p>其实我在2025年的7月就在我姐姐的电脑上装过Linux，还是双系统的，还了解到了UEFI、GPT、MBR这些，那个时候我都还没有自己的电脑呢</p><p>但也因为那时我没有自己的电脑，我一直没有深入使用linux，说白了就是“尝个鲜”，一台电脑才1TB，还得装下两个人的数据，能够用吗？不过也因为这个，我学习了很多Linux的知识，发行版和桌面换了好几个，zsh、fish也都用过，dnf apt pacman 都学会了，这也对我后来的Linux使用有很大帮助</p><p>但后来，2026年初的时候，我用压岁钱买了一台我自己的笔记本，虽然是二手的，但是有GTX1650，而且只花了1600，我觉得还是很值的</p><p>而我也用了Windows一段时间，但我实在忍不了它了，yarn装不上、命令补全没有、开机慢的要死、并且微软还经常加些奇奇怪怪的东西，让我觉得“这电脑到底是我的还是微软的免费广告牌？”，还莫名奇妙的蓝屏</p><p>所以我就改用了Linux</p><p>我做的第一步就是把我的分区都转成了btrfs格式，我超爱这个格式的，它非常快速！</p><p>然后我就开始安装系统，我先是安装了Ubuntu，但它太恶心了，神秘的snap使我的电脑卡的要死，中文支持稀烂</p><p>然后我又装了ZorinOS，然后发现它更垃圾😅</p><p>我就接连安装了Fedora、Manjaro、Bazaar OS</p><p>但最后我选择了Fedora，因为其他的都装不上</p><p>然后我优化了一下Gnome，装了主题和许多插件，Gnome真的是我见过的最好看的桌面环境了，虽然语言有点怪，但架不住扩展多</p><p>我把它改造成了Windows的样子，虽然我不喜欢Windows，但我还是习惯了它的操作方式，多亏了Dash to Panel插件</p><p><img src="'+i+'" alt="每日fastfetch"></p><p>我觉得它的软件生态真的没网上说的那么差，我要用的微信QQ和Chrome都有Linux版本，甚至我觉得Flathub上的软件比Windows上的还好</p><p>不知道怎么结尾所以结尾吧阿巴阿巴阿巴</p><br><br><br><br><br><br><br><br><br><br><br><br><br><br><br><br><br><br><br><br><br><br> ? 何意味',40)])])}const c=n(t,[["render",o]]);export{_ as __pageData,c as default};
